var UserConnection = Get<UserConnection>("UserConnection");

var Url = Get<string>("Url");
var EndPoint = Get<string>("EndPoint");
var Email = Get<string>("Email");
var RequestBody = Get<string>("RequestBody");
var ResponseBody = Get<string>("ResponseBody");

var httpReq = new HTTPRequest(Url, UserConnection);

var Data = new {
    Email = Email,
    RequestBody = RequestBody,
    ResponseBody = ResponseBody
};

var req = httpReq
    .SetLogName($"Send Email: Callback OP")
    .SetLogSection("NCCF v2 API")
	.Post(EndPoint, Data)
	.GetAwaiter()
	.GetResult();

return true;
